parameters.jsCode:
// Parse Claude's response to extract the structured task data
const claudeResponse = $input.first().json;
const content = claudeResponse.content[0].text;

// Parse the JSON from Claude's response
let parsed;
try {
  // Try to extract JSON if Claude wrapped it in markdown code blocks
  const jsonMatch = content.match(/```json?\n?([\s\S]*?)\n?```/) || content.match(/\{[\s\S]*\}/);
  const jsonStr = jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : content;
  parsed = JSON.parse(jsonStr);
} catch (e) {
  // Fallback if parsing fails
  parsed = {
    title: $input.first().json.title || 'Unparsed Task',
    project: 'Inbox',
    priority: 'Medium',
    tags: [],
    due_date: null,
    context: '@anywhere',
    estimated_minutes: 15
  };
}

return [{
  json: {
    ...parsed,
    original_text: items[0]?.json?.title || '',
    source: 'google-tasks-voice-capture',
    captured_at: new Date().toISOString()
  }
}];
